<?php namespace App\Repositories\Events;use App\Repositories\BaseRepository;use App\Models\Events\EventRegistration;use Illuminate\Database\Eloquent\Collection;class EventRegistrationRepository extends BaseRepository{    public function __construct(EventRegistration $model)    {        $this->model = $model;        parent::__construct($model);    }    public function findByEvent(int $eventId): Collection    {        return $this->findByField('event_id', $eventId);    }    public function findByStudent(int $studentId): Collection    {        return $this->findByField('student_id', $studentId);    }    public function findByStatus(string $status): Collection    {        return $this->findByField('status', $status);    }    public function getConfirmedRegistrations(int $eventId): Collection    {        return $this->query()->where('event_id', $eventId)->where('status', 'confirmed')->get();    }    public function getPendingRegistrations(int $eventId): Collection    {        return $this->query()->where('event_id', $eventId)->where('status', 'pending')->get();    }    public function confirmRegistration(int $id): bool    {        return $this->update($id, ['status' => 'confirmed', 'confirmed_at' => now()]);    }    public function cancelRegistration(int $id): bool    {        return $this->update($id, ['status' => 'cancelled', 'cancelled_at' => now()]);    }    public function checkRegistration(int $eventId, int $studentId): bool    {        return $this->query()->where('event_id', $eventId)->where('student_id', $studentId)->exists();    }    public function countByEvent(int $eventId): int    {        return $this->query()->where('event_id', $eventId)->where('status', 'confirmed')->count();    }    public function markAttendance(int $id): bool    {        return $this->update($id, ['attended' => true]);    }}